const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const bodyParser = require('body-parser');
const app = express();
const client = new Client({ node: 'http://localhost:9200' });

app.use(bodyParser.json());

app.post('/search', async (req, res) => {
    const { index, query, script } = req.body;

    if (!index || !query) {
        return res.status(400).send('Index and query are required.');
    }

    const sanitizedScript = sanitizeScript(script);

    const esQuery = {
        query: {
            script_score: {
                query: {
                    match: query
                },
                script: {
                    source: sanitizedScript
                }
            }
        }
    };

    try {
        const result = await client.search({
            index: index,
            body: esQuery
        });
        res.send(result.body.hits.hits);
    } catch (error) {
        res.status(500).send(error);
    }
});

function sanitizeScript(script) {
    const allowedFunctions = ['doc', 'params', 'Math'];
    const regex = new RegExp(`\\b(${allowedFunctions.join('|')})\\b`);
    if (!regex.test(script)) {
        throw new Error('Invalid script provided.');
    }
    return script;
}

const PORT = process.env.PORT || 3000;
